const tx = await wallet.writeContract({
  address: COLLECTION, abi: NFT_ABI,
  functionName: 'safeMint', args: [agent], value: mintFee
});
const receipt = await client.waitForTransactionReceipt({ hash: tx });
const mintedTokenId = receipt.logs.find(l => l.topics[0] === TRANSFER_TOPIC)?.topics[3];
const owner = await client.readContract({
  address: COLLECTION, abi: NFT_ABI, functionName: 'ownerOf', args: [BigInt(mintedTokenId)]
});
assert(owner.toLowerCase() === agent.toLowerCase());
